section.code:
{
  "$schema": "https://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/active-listening.json",
  "type": "object",
  "required": ["goal", "interviewee_profile", "receive_opener", "appreciate_phrases", "summarize_starters", "ask_questions", "reflective_prompts", "silence_cue"],
  "properties": {
    "goal": {"type": "string", "minLength": 10, "maxLength": 200},
    "interviewee_profile": {"type": "string", "minLength": 10, "maxLength": 300},
    "receive_opener": {"type": "string", "minLength": 10},
    "appreciate_phrases": {"type": "array", "items": {"type": "string"}, "minItems": 2, "maxItems": 5},
    "summarize_starters": {"type": "array", "items": {"type": "string"}, "minItems": 3, "maxItems": 5},
    "ask_questions": {
      "type": "array",
      "items": {"type": "string", "pattern": "^(What|How|Tell me|Walk me|Describe|Help me understand|In what way)"},
      "minItems": 5,
      "maxItems": 8
    },
    "reflective_prompts": {
      "type": "array",
      "items": {"type": "string", "pattern": "(sounds like|seems like|I hear that)"},
      "minItems": 1
    },
    "silence_cue": {"type": "string", "minLength": 10},
    "channel": {"enum": ["live-voice", "live-video", "async-text"]}
  }
}

example.code:
{
  "goal": "Get info",
  "ask_questions": ["Is the system slow?", "Do you like it?"]
}
